import React from "react";
import { motion } from "framer-motion";

const experiences = [
  {
    id: 1,
    title: "Skydiving Adventure",
    description: "Experience the thrill of freefall from 15,000 feet!",
    image:
      "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?fit=crop&w=400",
  },
  {
    id: 2,
    title: "Mountain Hiking",
    description: "Explore breathtaking mountains and nature trails.",
    image:
      "https://images.unsplash.com/photo-1501785888041-af3ef285b470?fit=crop&w=400",
  },
  {
    id: 3,
    title: "Scuba Diving",
    description: "Dive into the ocean and discover marine life.",
    image:
      "https://images.unsplash.com/photo-1470770903676-69b98201ea1c?fit=crop&w=400",
  },
];

function Experience() {
  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-100 via-purple-100 to-pink-100 py-10">
      {/* Page Title */}
      <motion.h1
        className="text-4xl sm:text-5xl font-extrabold text-center text-transparent bg-clip-text bg-gradient-to-r from-blue-600 to-pink-500 mb-12"
        initial={{ opacity: 0, y: -30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8 }}
      >
        Unforgettable Experiences 🌍
      </motion.h1>

      {/* Experience Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-10 px-8 md:px-16">
        {experiences.map((exp) => (
          <motion.div
            key={exp.id}
            whileHover={{ scale: 1.07, rotate: 1 }}
            whileTap={{ scale: 0.97 }}
            transition={{ type: "spring", stiffness: 200 }}
            className="bg-white/90 backdrop-blur-md border border-gray-200 shadow-lg hover:shadow-2xl rounded-3xl overflow-hidden transform duration-300"
          >
            <div className="relative">
              <img
                src={
                  exp.image ||
                  "https://via.placeholder.com/400x250?text=No+Image+Available"
                }
                alt={exp.title}
                className="w-full h-56 object-cover"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent" />
            </div>

            <div className="p-6 text-center">
              <h3 className="text-2xl font-semibold text-gray-800 mb-2">
                {exp.title}
              </h3>
              <p className="text-gray-600 text-sm mb-4 leading-relaxed">
                {exp.description}
              </p>
              <motion.button
                whileHover={{ scale: 1.1 }}
                className="bg-gradient-to-r from-blue-600 to-pink-500 text-white font-medium px-5 py-2 rounded-full shadow-md hover:shadow-xl transition-all duration-300"
              >
                Learn More
              </motion.button>
            </div>
          </motion.div>
        ))}
      </div>
    </div>
  );
}

export default Experience;
